    {
      "tool": "iam.check_permission",
      "arguments": {
        "action": "create_slack_channel",
        "resource": "slack://channels/*"
      },
      "depends_on": []
    },
    {
      "tool": "slack.post_message",
      "arguments": {
        "channel": "#incident-response",
        "message": "🚨 **Creating incident response channel for affected service...**"
      },
      "depends_on": [1]
    },
    {
      "tool": "mongo.find",
      "arguments": {
        "collection": "incident_metadata",
        "filter": {
          "status": "active",
          "incident_type": "service_error"
        }
      },
      "depends_on": [1]
    },
    {
      "tool": "mongo.aggregate",
      "arguments": {
        "collection": "logs_summary",
        "pipeline": [
          {
            "$match": {
              "source": "step_2_fetch_logs"
            }
          },
          {
            "$group": {
              "_id": "$error_pattern",
              "count": { "$sum": 1 },
              "affected_services": { "$addToSet": "$service_name" },
              "latest_timestamp": { "$max": "$timestamp" }
            }
          },
          {
            "$sort": { "count": -1 }
          }
        ]
      },
      "depends_on": [1]
    },
    {
      "tool": "datadog.query_metric",
      "arguments": {
        "metric": "system.cpu.user,system.memory.usage,aws.apigateway.4xxerror,aws.apigateway.5xxerror",
        "window": "last_1h",
        "group_by": ["service", "error_type"]
      },
      "depends_on": [4]
    },
    {
      "tool": "slack.post_message",
      "arguments": {
        "channel": "#$3.service_name-incident",
